#nullable enable // autogenerated

using System;
using MVZ2.GameContent.Maps;
using MVZ2.Vanilla.ChapterTransitions;
using MVZ2.Vanilla.Localization;
using MVZ2Logic;
using MVZ2Logic.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.Commands;
using MVZ2Logic.Definitions;
using MVZ2Logic.Localization;
using MVZ2Logic.Saves;
using PVZEngine;

namespace MVZ2.GameContent.Commands
{
    [AutoCommandDefinition(VanillaCommandNames.chapterTransition)]
    public class ChapterTransition : CommandDefinition
    {
        public ChapterTransition(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Invoke(string[] parameters)
        {
            var game = Global.Game;
            var level = Global.Level;
            if (level.IsInLevel())
            {
                throw new ArgumentException(Global.Localization.GetTextParticular(VanillaStrings.COMMAND_CANNOT_BE_CALLED_IN_LEVEL, LogicStrings.CONTEXT_COMMAND_OUTPUT));
            }

            if (parameters[0] == "start")
            {
                var id = NamespaceID.Parse(parameters[1], Global.BuiltinNamespace);
                Global.Music.Stop();
                game.StartCoroutine(VanillaChapterTransitions.TransitionToMap(id, Global.Saves.GetLastMapID() ?? VanillaMapID.halloween, false));
            }
            else if (parameters[0] == "end")
            {
                var id = NamespaceID.Parse(parameters[1], Global.BuiltinNamespace);
                Global.Music.Stop();
                game.StartCoroutine(VanillaChapterTransitions.TransitionToMap(id, Global.Saves.GetLastMapID() ?? VanillaMapID.halloween, true));
            }
        }
    }
}